    }

    // Check for potential overflow when casting to int
    if (dictSize > Integer.MAX_VALUE) {
        throw new IOException("Dictionary size exceeds maximum int value");
    }

    return new LZMAInputStream(in, -1, propsByte, (int) dictSize);
}
```

### Changes Made:
